import { test, expect } from '@playwright/test';

test('Amazon SG - Add product to cart and validate cart page', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/', { waitUntil: 'domcontentloaded' });

  // 2. Add product to cart.
  // Search for a product (e.g., "laptop")
  const searchBox = page.locator('input#twotabsearchtextbox');
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('laptop');
  await page.getByRole('button', { name: 'Go' }).click();

  // Wait for search results to load
  const firstProduct = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first();
  await expect(firstProduct).toBeVisible({ timeout: 15000 });

  // Click the first product link
  const productLink = firstProduct.locator('h2 a');
  await productLink.click();

  // Wait for product page to load
  await expect(page.getByRole('button', { name: /Add to Cart/i })).toBeVisible({ timeout: 15000 });

  // Click "Add to Cart"
  await page.getByRole('button', { name: /Add to Cart/i }).click();

  // Wait for cart confirmation or side sheet
  const cartConfirmation = page.locator('h1').filter({ hasText: 'Added to Cart' });
  const cartSideSheet = page.locator('div#attach-added-to-cart-message');
  await Promise.race([
    cartConfirmation.waitFor({ timeout: 10000 }).catch(() => {}),
    cartSideSheet.waitFor({ timeout: 10000 }).catch(() => {}),
    page.waitForTimeout(3000) // fallback short wait
  ]);

  // 3. Click cart icon (id="nav-cart").
  const cartIcon = page.locator('#nav-cart');
  await expect(cartIcon).toBeVisible({ timeout: 10000 });
  await cartIcon.click();

  // 4. Validate cart page loads.
  await expect(page).toHaveURL(/.*\/gp\/cart\/view\.html.*/);
  const cartHeader = page.getByText('Shopping Cart', { exact: true });
  await expect(cartHeader).toBeVisible({ timeout: 10000 });

  // 5. Close browser.
  // (Playwright test runner handles browser closure automatically)
});
